if __name__=="__main__":
    print("GRC Batch 6 — ISO + HIPAA...")
    data={"id":"iso-27001-batch2","name":"ISO 27001:2022 (Batch 2)","description":"Additional ISO 27001 Annex A controls","controls":ISO6}
    with open(OUTPUT_DIR/"iso_27001_batch2.json",'w') as f: json.dump(data,f,indent=2)
    print(f"  ISO batch 2: {len(ISO6)}")
    data={"id":"hipaa","name":"HIPAA","description":"Health Insurance Portability and Accountability Act — Security Rule","controls":HIPAA}
    with open(OUTPUT_DIR/"hipaa.json",'w') as f: json.dump(data,f,indent=2)
    print(f"  HIPAA: {len(HIPAA)}")
    # Add policies
    POLICY_DIR.mkdir(parents=True, exist_ok=True)
    policies = {
        "password_policy": "# Password Policy\n\n## 1. Purpose\nEstablish requirements for creating and managing passwords.\n\n## 2. Requirements\n- Minimum 14 characters\n- Mix of uppercase, lowercase, numbers, symbols\n- No dictionary words or personal info\n- Change every 90 days (or on compromise)\n- MFA required for all remote access\n- No password reuse (last 12)\n\n## 3. Storage\n- Passwords stored using bcrypt/argon2\n- Never stored in plaintext\n- Password managers encouraged\n\n## 4. Enforcement\nNon-compliance results in account lockout and disciplinary action.",
        "vendor_management": "# Vendor Management Policy\n\n## 1. Purpose\nManage security risks from third-party vendors and service providers.\n\n## 2. Vendor Assessment\n- Security questionnaire for all new vendors\n- Annual reassessment for critical vendors\n- SOC 2 or ISO 27001 certification preferred\n\n## 3. Contracts\n- Include data protection clauses\n- Right-to-audit provisions\n- Breach notification requirements (72 hours)\n- Data return/destruction on termination\n\n## 4. Monitoring\n- Review vendor security posture quarterly\n- Monitor for vendor breaches\n- Maintain vendor risk register",
        "data_classification": "# Data Classification Policy\n\n## 1. Classification Levels\n\n| Level | Description | Examples |\n|-------|-------------|----------|\n| Public | No restrictions | Marketing materials |\n| Internal | Business use only | Internal memos |\n| Confidential | Restricted access | Financial data, PII |\n| Restricted | Highest protection | Trade secrets, PHI |\n\n## 2. Handling Requirements\n- Public: No special handling\n- Internal: Don't share externally\n- Confidential: Encrypt in transit/rest, access control\n- Restricted: Encrypt always, MFA, audit logging, DLP\n\n## 3. Labeling\nAll documents must be labeled with classification level.",
        "change_management": "# Change Management Policy\n\n## 1. Purpose\nEnsure all changes to IT systems are planned, tested, approved, and documented.\n\n## 2. Change Types\n- Standard: Pre-approved, low risk\n- Normal: Requires CAB approval\n- Emergency: Expedited approval, post-review\n\n## 3. Process\n1. Submit change request\n2. Impact assessment\n3. Testing in non-production\n4. CAB review and approval\n5. Implementation with rollback plan\n6. Post-implementation review\n\n## 4. Documentation\nAll changes recorded in change management system with before/after states.",
        "business_continuity": "# Business Continuity Policy\n\n## 1. Purpose\nEnsure critical business functions continue during and after a disruption.\n\n## 2. Key Definitions\n- RTO: Maximum acceptable downtime\n- RPO: Maximum acceptable data loss\n- MTPD: Maximum tolerable period of disruption\n\n## 3. Requirements\n- BIA conducted annually\n- BCP tested semi-annually\n- DR site maintained\n- Communication plan established\n\n## 4. Critical Functions\nIdentified through Business Impact Analysis with assigned RTOs and RPOs.",
    }
    for name, content in policies.items():
        with open(POLICY_DIR/f"{name}.md",'w') as f: f.write(content)
    print(f"  Policies: {len(policies)} new")
    # Total
    total=0
    for fp in OUTPUT_DIR.glob("*.json"):
        with open(fp) as f:
            d=json.load(f)
            if isinstance(d,list): total+=len(d)
            elif "controls" in d: total+=len(d["controls"])
    print(f"\n  TOTAL CONTROLS: {total}")
